// Outer class definition
public class Outer {
    private int value = 10;

    // 1. Static nested class
    static class StaticNested {
        // show method definition
        void show() {
            // Cannot access value (because it's static)
            System.out.println("static nested");
        }
    }

    // 2. Member class (inner class)
    // Inner class definition
    class Inner {
        // show method definition
        void show() {
            // Can access the outer class's field
            System.out.println("inner: " + value);
        }
    }

    void method() {
        // 3. Local class
        // Local class definition
        class Local {
            void show() {
                System.out.println("local: " + value);
            }
        }
        new Local().show();

        // 4. Anonymous class
        Runnable r = new Runnable() {
            @Override
            public void run() {
                System.out.println("anonymous: " + value);
            }
        };
        r.run();
    }
}

public class Outer {
    private static int staticVal = 100;
    private int instanceVal = 200;

    // Static nested class
    static class StaticNested {
        void show() {
            System.out.println(staticVal);    // ✅ Can access static members
            // System.out.println(instanceVal); // ❌ Cannot access instance members
        }

        static void staticMethod() {
            System.out.println("static nested static method");
        }
    }
}

public class Main {
    public static void main(String[] args) {
        // Instantiating a static nested class
        // No instance of the outer class is needed
        Outer.StaticNested sn = new Outer.StaticNested();
        sn.show();

        // Calling a static method
        Outer.StaticNested.staticMethod();
    }
}

// Outer class definition
public class Outer {
    private int value = 42;

    // Inner class definition
    class Inner {
        private int value = 99;

        // show method definition
        void show() {
            System.out.println(value);            // 99 (Inner.this.value)
            System.out.println(this.value);        // 99 (this = Inner)
            System.out.println(Outer.this.value);  // 42 (outer class reference)
        }
    }
}

// Main class definition
public class Main {
    // main method definition
    public static void main(String[] args) {
        // Instantiating a member class
        // An instance of the outer class is required!
        Outer outer = new Outer();
        Outer.Inner inner = outer.new Inner();
        //                    ↑ Note the outer.new syntax
        inner.show();

        // Writing it in one line
        Outer.Inner inner2 = new Outer().new Inner();
    }
}

