public class Outer {
    private String name = "Outer";

    void process(String prefix) {
        int count = 5;  // Effectively final (never reassigned)

        // Local class definition
        class Helper {
            void execute() {
                // Can access outer class fields
                System.out.println(name);
                // Can access method local variables
                // (but must be effectively final)
                System.out.println(prefix + count);
            }
        }

        // Instantiating the local class
        Helper h = new Helper();
        h.execute();

        // count = 10; // If this exists, count in Helper causes a compilation error
    }
}

