// Main class definition
public class Main {
    // Anonymous implementation of an interface
    // main method definition
    public static void main(String[] args) {
        // Anonymous class implementation of Comparator
        List<String> names = new ArrayList<>(List.of("Charlie", "Alice", "Bob"));

        Comparator<String> comp = new Comparator<String>() {
            @Override
            // compare method definition
            public int compare(String a, String b) {
                return a.length() - b.length();  // Compare by string length
            }
        };
        names.sort(comp);
        System.out.println(names); // [Bob, Alice, Charlie]

        // Anonymous subclass of an abstract class
        // Greeting class definition
        abstract class Greeting {
            abstract String message();
        }
        Greeting g = new Greeting() {
            @Override
            String message() {
                return "Hello";
            }
        };
        System.out.println(g.message());

        // Overriding a concrete class is also possible
        Object obj = new Object() {
            @Override
            public String toString() {
                return "Custom Object";
            }
        };
        System.out.println(obj); // Custom Object
    }
}

