import java.util.Comparator;
import java.util.function.Predicate;

// Main class definition
public class Main {
    // main method definition
    public static void main(String[] args) {
        // Anonymous class version
        Comparator<String> comp1 = new Comparator<String>() {
            @Override
            // compare method definition
            public int compare(String a, String b) {
                return a.length() - b.length();
            }
        };

        // Lambda expression version (type inference for parameters is also possible)
        Comparator<String> comp2 = (a, b) -> a.length() - b.length();

        // Predicate example
        Predicate<String> isLong1 = new Predicate<String>() {
            @Override
            public boolean test(String s) {
                return s.length() > 5;
            }
        };
        Predicate<String> isLong2 = s -> s.length() > 5;

        // Runnable example
        Runnable r1 = new Runnable() {
            @Override
            public void run() {
                System.out.println("Hello");
            }
        };
        Runnable r2 = () -> System.out.println("Hello");
    }
}

public class Outer {
    private String name = "Outer";

    void test() {
        // Anonymous class: this refers to the anonymous class itself
        Runnable r1 = new Runnable() {
            @Override
            public void run() {
                // this → instance of the anonymous class
                System.out.println(this.getClass().getSimpleName());
                // Output: "" (anonymous class has no name)
            }
        };

        // Lambda expression: this refers to the outer class (Outer)
        Runnable r2 = () -> {
            // this → instance of Outer
            System.out.println(this.name);
            // Output: "Outer"
        };

        r1.run();
        r2.run();
    }
}

